import{_ as t,a as e,b as r,c as l}from"./chunks/下载好后的视频.pSSnkGgz.js";import{_ as n,o as i,c as d,a2 as o}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Magnet Transfer","description":"","frontmatter":{},"headers":[],"relativePath":"ru-RU/Other/magnet-transfer.md","filePath":"ru-RU/Other/magnet-transfer.md","lastUpdated":1781962217000}'),s={name:"ru-RU/Other/magnet-transfer.md"};function h(p,a,m,c,g,u){return i(),d("div",null,[...a[0]||(a[0]=[o('<h1 id="magnet-transfer" tabindex="-1">Magnet Transfer <a class="header-anchor" href="#magnet-transfer" aria-label="Permalink to &quot;Magnet Transfer&quot;">​</a></h1><p>Magnet transfer скачивает файлы по magnet link и автоматически загружает их в выбранный cloud storage channel.</p><p>Это удобно для переноса anime-серий, видео, архивов и похожих файлов. Вставьте magnet link, и ImgBed создаст фоновую задачу загрузки. После завершения файл будет загружен в ImgBed, а финальная ссылка появится в списке загрузок.</p><p><img src="'+t+'" alt="Magnet transfer" loading="lazy"></p><h2 id="где-использовать" tabindex="-1">Где использовать <a class="header-anchor" href="#где-использовать" aria-label="Permalink to &quot;Где использовать&quot;">​</a></h2><p>Вход для magnet transfer находится в зоне загрузки на главной странице.</p><p>Вставьте magnet link в поле ввода, выберите <code>Transfer</code>, затем загрузите.</p><p><img src="'+e+'" alt="Загрузка anime" loading="lazy"></p><h2 id="перед-первым-использованием" tabindex="-1">Перед первым использованием <a class="header-anchor" href="#перед-первым-использованием" aria-label="Permalink to &quot;Перед первым использованием&quot;">​</a></h2><p>Сначала настройте magnet transfer в админ-панели.</p><p>Обычно нужны:</p><ol><li>GitHub-аккаунт для запуска download task.</li><li>Cloud upload channel, например Google Drive или OneDrive.</li><li>Целевая upload directory.</li><li>Task timeout.</li></ol><p>Когда настройки готовы, вернитесь на главную страницу и вставьте magnet link, чтобы начать transfer.</p><h2 id="загрузка-magnet-link" tabindex="-1">Загрузка magnet link <a class="header-anchor" href="#загрузка-magnet-link" aria-label="Permalink to &quot;Загрузка magnet link&quot;">​</a></h2><ol><li>Вставьте magnet link в поле загрузки на главной странице.</li><li>Убедитесь, что режим установлен как <code>Transfer</code>.</li><li>Нажмите upload.</li><li>Дождитесь, пока ImgBed создаст magnet task.</li><li>После запуска задачи используйте плавающую панель <code>Magnet Tasks</code> в правом нижнем углу, чтобы следить за прогрессом.</li></ol><p>Download и upload могут занять время. Скорость зависит от magnet-ресурса, среды GitHub runtime и выбранного cloud storage channel.</p><p><img src="'+r+'" alt="Magnet скачивается" loading="lazy"></p><h2 id="после-завершения" tabindex="-1">После завершения <a class="header-anchor" href="#после-завершения" aria-label="Permalink to &quot;После завершения&quot;">​</a></h2><p>После завершения задачи в списке загрузок появятся имя файла и ссылка.</p><p>Для видео показывается video preview, для изображений — image preview, а для остальных файлов — обычная иконка файла.</p><p><img src="'+l+'" alt="Скачанное видео" loading="lazy"></p><p>Можно скопировать:</p><table tabindex="0"><thead><tr><th>Тип ссылки</th><th>Для чего</th></tr></thead><tbody><tr><td>Original link</td><td>Прямой доступ к файлу</td></tr><tr><td>Markdown</td><td>Markdown-посты или заметки</td></tr><tr><td>HTML</td><td>Код веб-страницы</td></tr><tr><td>BBCode</td><td>Форумы с поддержкой BBCode</td></tr></tbody></table><h2 id="панель-magnet-task" tabindex="-1">Панель Magnet Task <a class="header-anchor" href="#панель-magnet-task" aria-label="Permalink to &quot;Панель Magnet Task&quot;">​</a></h2><p>Панель magnet task в правом нижнем углу показывает количество задач, название, прогресс и финальный статус.</p><p>Типичные состояния:</p><table tabindex="0"><thead><tr><th>Статус</th><th>Значение</th></tr></thead><tbody><tr><td>Waiting</td><td>Задача создана и ждет запуска.</td></tr><tr><td>Downloading</td><td>Magnet-ресурс скачивается.</td></tr><tr><td>Uploading</td><td>Файл скачан и передается в cloud storage.</td></tr><tr><td>Completed</td><td>Upload успешен, ссылку можно копировать.</td></tr><tr><td>Failed</td><td>Задача не завершилась успешно. Проверьте сообщение и попробуйте снова.</td></tr></tbody></table><h2 id="советы" tabindex="-1">Советы <a class="header-anchor" href="#советы" aria-label="Permalink to &quot;Советы&quot;">​</a></h2><ul><li>Если magnet link содержит несколько файлов, ImgBed старается показать основной завершенный файл.</li><li>Большие файлы требуют больше времени. Дождитесь завершения задачи перед обновлением страницы.</li><li>Если у magnet-ресурса нет доступных peers, он может быть очень медленным или не скачаться.</li><li>Если в cloud account закончилась квота, authorization истекла или upload directory указана неверно, задача может завершиться ошибкой.</li><li>Video preview может появиться через несколько секунд после завершения upload.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="после-вставки-magnet-link-ничего-не-запускается" tabindex="-1">После вставки Magnet Link ничего не запускается <a class="header-anchor" href="#после-вставки-magnet-link-ничего-не-запускается" aria-label="Permalink to &quot;После вставки Magnet Link ничего не запускается&quot;">​</a></h3><p>Убедитесь, что magnet transfer включен в админ-панели, а также выбран пригодный GitHub-аккаунт и cloud channel.</p><h3 id="скачивание-всегда-медленное" tabindex="-1">Скачивание всегда медленное <a class="header-anchor" href="#скачивание-всегда-медленное" aria-label="Permalink to &quot;Скачивание всегда медленное&quot;">​</a></h3><p>Скорость magnet зависит от самого ресурса. Если нет доступных peers, скачивание может быть очень медленным или невозможным.</p><h3 id="после-upload-нет-preview" tabindex="-1">После upload нет preview <a class="header-anchor" href="#после-upload-нет-preview" aria-label="Permalink to &quot;После upload нет preview&quot;">​</a></h3><p>Сначала проверьте, открывается ли ссылка на файл. Видеофайлам может понадобиться немного времени для загрузки в браузере; также можно открыть ссылку напрямую.</p><h3 id="что-проверить-если-task-failed" tabindex="-1">Что проверить, если task failed? <a class="header-anchor" href="#что-проверить-если-task-failed" aria-label="Permalink to &quot;Что проверить, если task failed?&quot;">​</a></h3><p>Проверьте, действителен ли magnet link, работает ли cloud channel и правильна ли upload directory. Затем отправьте задачу еще раз.</p>',38)])])}const _=n(s,[["render",h]]);export{b as __pageData,_ as default};
